import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

export default function LabourDashboard() {

  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/jobs/all")
      .then((res) => setJobs(res.data));
  }, []);

  const acceptJob = async (id) => {
    await axios.put(
      `http://localhost:5000/api/jobs/accept/${id}`
    );

    window.location.reload();
  };

  const rejectJob = async (id) => {
    await axios.put(
      `http://localhost:5000/api/jobs/reject/${id}`
    );

    window.location.reload();
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.headerBox}>

          <div>
            <h1 style={styles.heading}>
              Job Requests
            </h1>

            <p style={styles.subText}>
              Manage customer booking requests.
            </p>
          </div>

          <div style={styles.statsCard}>
            <h3>Total Requests</h3>
            <p>{jobs.length}</p>
          </div>

        </div>

        <div style={styles.grid}>

          {jobs.map((job) => (

            <div key={job._id} style={styles.card}>

              <div style={styles.topRow}>

                <div style={styles.avatar}>
                  {job.workerName?.charAt(0)}
                </div>

                <div>
                  <h2>{job.workerName}</h2>

                  <p style={styles.status}>
                    {job.status}
                  </p>
                </div>

              </div>

              <div style={styles.infoBox}>

                <p>
                  <strong>Work Type:</strong>
                </p>

                <p>{job.workType}</p>

              </div>

              <div style={styles.infoBox}>

                <p>
                  <strong>Preferred Time Slots:</strong>
                </p>

                <ul>
                  {job.timeSlots?.map((slot, index) => (
                    <li key={index}>{slot}</li>
                  ))}
                </ul>

              </div>

              <div style={styles.priceBox}>

                <h3>₹ {job.price}</h3>

              </div>

              <div style={styles.btnRow}>

                <button
                  style={styles.acceptBtn}
                  onClick={() => acceptJob(job._id)}
                >
                  Accept
                </button>

                <button
                  style={styles.rejectBtn}
                  onClick={() => rejectJob(job._id)}
                >
                  Reject
                </button>

              </div>

            </div>
          ))}

        </div>

      </div>

      <Footer />

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px"
  },

  headerBox: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "30px"
  },

  heading: {
    fontSize: "38px",
    color: "#111827"
  },

  subText: {
    color: "#6b7280"
  },

  statsCard: {
    background: "white",
    padding: "20px",
    borderRadius: "16px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.08)",
    textAlign: "center",
    width: "180px"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(320px,1fr))",
    gap: "25px"
  },

  card: {
    background: "white",
    borderRadius: "20px",
    padding: "25px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.08)"
  },

  topRow: {
    display: "flex",
    alignItems: "center",
    gap: "15px"
  },

  avatar: {
    width: "60px",
    height: "60px",
    borderRadius: "50%",
    background: "#22c55e",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontSize: "24px",
    fontWeight: "bold"
  },

  status: {
    color: "#2563eb",
    textTransform: "capitalize"
  },

  infoBox: {
    marginTop: "20px"
  },

  priceBox: {
    marginTop: "20px"
  },

  btnRow: {
    display: "flex",
    gap: "15px",
    marginTop: "25px"
  },

  acceptBtn: {
    flex: 1,
    background: "#22c55e",
    color: "white",
    border: "none",
    padding: "14px",
    borderRadius: "10px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "14px",
    borderRadius: "10px",
    cursor: "pointer"
  }
};
